/**
 * WiFi开关事件回调
 */
static void ui_event_WiFiSwitch(lv_event_t * e)
{
    lv_event_code_t event_code = lv_event_get_code(e);
    if(event_code == LV_EVENT_VALUE_CHANGED) {
        wifi_enabled = lv_obj_has_state(ui_Switch2, LV_STATE_CHECKED);

        if(wifi_enabled) {
            // 打开WiFi：blueXPanel7背景变蓝色（blueXPanel7是WiFi开关面板）
            lv_obj_set_style_bg_color(ui_blueXPanel7, lv_color_hex(0x207864), LV_PART_MAIN | LV_STATE_DEFAULT);

            // 扫描并显示WiFi设备列表
            char device_names[MAX_DEVICE_COUNT][32];
            int count = 0;

            // 调用硬件接口扫描WiFi设备
            wifi_scan_devices(device_names, &count);

            wifi_device_count = 0;
            for(int i = 0; i < count && i < MAX_DEVICE_COUNT; i++) {
                ui_create_wifi_device_item(device_names[i]);
            }

            // 显示WiFi列表
            lv_obj_clear_flag(ui_WiFiPanel7, LV_OBJ_FLAG_HIDDEN);
        } else {
            // 关闭WiFi：恢复默认背景色，隐藏列表
            lv_obj_set_style_bg_color(ui_blueXPanel7, lv_color_hex(0xE6E2E6), LV_PART_MAIN | LV_STATE_DEFAULT);
            lv_obj_add_flag(ui_WiFiPanel7, LV_OBJ_FLAG_HIDDEN);

            // 断开连接
            if(connected_wifi[0] != '\0') {
                wifi_disconnect();
                connected_wifi[0] = '\0';
            }
        }
    }
}

