/**
 * WiFi设备点击事件回调
 */
static void ui_event_WiFiDeviceClick(lv_event_t * e)
{
    lv_event_code_t event_code = lv_event_get_code(e);
    if(event_code == LV_EVENT_CLICKED) {
        const char *wifi_name = (const char *)lv_event_get_user_data(e);

        // 调用硬件接口连接WiFi
        if(wifi_connect(wifi_name)) {
            // 连接成功，保存已连接的WiFi名称
            strcpy(connected_wifi, wifi_name);

            // 更新所有WiFi设备项的背景色
            for(int i = 0; i < wifi_device_count; i++) {
                const char *device_name = lv_label_get_text(wifi_devices[i].name);
                if(strcmp(device_name, wifi_name) == 0) {
                    // 已连接的WiFi设置蓝色背景
                    lv_obj_set_style_bg_color(wifi_devices[i].panel, lv_color_hex(0x207864), LV_PART_MAIN | LV_STATE_DEFAULT);
                } else {
                    // 其他WiFi设置默认背景色
                    lv_obj_set_style_bg_color(wifi_devices[i].panel, lv_color_hex(0x9CA5A4), LV_PART_MAIN | LV_STATE_DEFAULT);
                }
            }
        }
    }
}

